"""
Parameterized generator for GH701_zap_1443.

Source PR:    https://github.com/uber-go/zap/pull/1443
Source Issue: N/A

Seed varies: renames 'after' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH701_zap_1443'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH701_zap_1443'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('after', 'after' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH701_zap_1443',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'uber-go/zap',
                "pr_number": 1443,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/uber-go/zap/pull/1443",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'Makefile': '# Directory containing the Makefile.\nPROJECT_ROOT = $(dir $(abspath $(lastword $(MAKEFILE_LIST))))\n\nexport GOBIN ?= $(PROJECT_ROOT)/bin\nexport PATH := $(GOBIN):$(PATH)\n\nGOVULNCHECK = $(GOBIN)/govulncheck\nBENCH_FLAGS ?= -cpuprofile=cpu.pprof -memprofile=mem.pprof -benchmem\n\n# Directories containing independent Go modules.\nMODULE_DIRS = . ./exp ./benchmarks ./zapgrpc/internal/test\n\n# Directories that we want to track coverage for.\nCOVER_DIRS = . ./exp\n\n.PHONY: all\nall: lint test\n\n.PHONY: lint\nlint: golangci-lint tidy-lint license-lint\n\n.PHONY: golangci-lint\ngolangci-lint:\n\t@$(foreach mod,$(MODULE_DIRS), \\\n\t\t(cd $(mod) && \\\n\t\techo "[lint] golangci-lint: $(mod)" && \\\n\t\tgolangci-lint run --path-prefix $(mod)) &&) true\n\n.PHONY: tidy\ntidy:\n\t@$(foreach dir,$(MODULE_DIRS), \\\n\t\t(cd $(dir) && go mod tidy) &&) true\n\n.PHONY: tidy-lint\ntidy-lint:\n\t@$(foreach mod,$(MODULE_DIRS), \\\n\t\t(cd $(mod) && \\\n\t\techo "[lint] tidy: $(mod)" && \\\n\t\tgo mod tidy && \\\n\t\tgit diff --exit-code -- go.mod go.sum) &&) true\n\n\n.PHONY: license-lint\nlicense-lint:\n\t./checklicense.sh\n\n$(GOVULNCHECK):\n\tcd tools && go install golang.org/x/vuln/cmd/govulncheck\n\n.PHONY: test\ntest:\n\t@$(foreach dir,$(MODULE_DIRS),(cd $(dir) && go test -race ./...) &&) true\n\n.PHONY: cover\ncover:\n\t@$(foreach dir,$(COVER_DIRS), ( \\\n\t\tcd $(dir) && \\\n\t\tgo test -race -coverprofile=cover.out -coverpkg=./... ./... \\\n\t\t&& go tool cover -html=cover.out -o cover.html) &&) true\n\n.PHONY: bench\nBENCH ?= .\nbench:\n\t@$(foreach dir,$(MODULE_DIRS), ( \\\n\t\tcd $(dir) && \\\n\t\tgo list ./... | xargs -n1 go test -bench=$(BENCH) -run="^$$" $(BENCH_FLAGS) \\\n\t) &&) true\n\n.PHONY: updatereadme\nupdatereadme:\n\trm -f README.md\n\tcat .readme.tmpl | go run internal/readme/readme.go > README.md\n\n.PHONY: vulncheck\nvulncheck: $(GOVULNCHECK)\n\t$(GOVULNCHECK) ./...\n',
            'http_handler.go': '// Copyright (c) 2016 Uber Technologies, Inc.\n//\n// Permission is hereby granted, free of charge, to any person obtaining a copy\n// of this software and associated documentation files (the "Software"), to deal\n// in the Software without restriction, including without limitation the rights\n// to use, copy, modify, merge, publish, distribute, sublicense, and/or sell\n// copies of the Software, and to permit persons to whom the Software is\n// furnished to do so, subject to the following conditions:\n//\n// The above copyright notice and this permission notice shall be included in\n// all copies or substantial portions of the Software.\n//\n// THE SOFTWARE IS PROVIDED "AS IS", WITHOUT WARRANTY OF ANY KIND, EXPRESS OR\n// IMPLIED, INCLUDING BUT NOT LIMITED TO THE WARRANTIES OF MERCHANTABILITY,\n// FITNESS FOR A PARTICULAR PURPOSE AND NONINFRINGEMENT. IN NO EVENT SHALL THE\n// AUTHORS OR COPYRIGHT HOLDERS BE LIABLE FOR ANY CLAIM, DAMAGES OR OTHER\n// LIABILITY, WHETHER IN AN ACTION OF CONTRACT, TORT OR OTHERWISE, ARISING FROM,\n// OUT OF OR IN CONNECTION WITH THE SOFTWARE OR THE USE OR OTHER DEALINGS IN\n// THE SOFTWARE.\n\npackage zap\n\nimport (\n\t"encoding/json"\n\t"errors"\n\t"fmt"\n\t"io"\n\t"net/http"\n\n\t"go.uber.org/zap/zapcore"\n)\n\n// ServeHTTP is a simple JSON endpoint that can report on or change the current\n// logging level.\n//\n// # GET\n//\n// The GET request returns a JSON description of the current logging level like:\n//\n//\t{"level":"info"}\n//\n// # PUT\n//\n// The PUT request changes the logging level. It is perfectly safe to change the\n// logging level while a program is running. Two content types are supported:\n//\n//\tContent-Type: application/x-www-form-urlencoded\n//\n// With this content type, the level can be provided through the request body or\n// a query parameter. The log level is URL encoded like:\n//\n//\tlevel=debug\n//\n// The request body takes precedence over the query parameter, if both are\n// specified.\n//\n// This content type is the default for a curl PUT request. Following are two\n// example curl requests that both set the logging level to debug.\n//\n//\tcurl -X PUT localhost:8080/log/level?level=debug\n//\tcurl -X PUT localhost:8080/log/level -d level=debug\n//\n// For any other content type, the payload is expected to be JSON encoded and\n// look like:\n//\n//\t{"level":"info"}\n//\n// An example curl request could look like this:\n//\n//\tcurl -X PUT localhost:8080/log/level -H "Content-Type: application/json" -d \'{"level":"debug"}\'\nfunc (lvl AtomicLevel) ServeHTTP(w http.ResponseWriter, r *http.Request) {\n\tif err := lvl.serveHTTP(w, r); err != nil {\n\t\tw.WriteHeader(http.StatusInternalServerError)\n\t\tfmt.Fprintf(w, "internal error: %v", err)\n\t}\n}\n\nfunc (lvl AtomicLevel) serveHTTP(w http.ResponseWriter, r *http.Request) error {\n\ttype errorResponse struct {\n\t\tError string `json:"error"`\n\t}\n\ttype payload struct {\n\t\tLevel zapcore.Level `json:"level"`\n\t}\n\n\tenc := json.NewEncoder(w)\n\n\tswitch r.Method {\n\tcase http.MethodGet:\n\t\treturn enc.Encode(payload{Level: lvl.Level()})\n\n\tcase http.MethodPut:\n\t\trequestedLvl, err := decodePutRequest(r.Header.Get("Content-Type"), r)\n\t\tif err != nil {\n\t\t\tw.WriteHeader(http.StatusBadRequest)\n\t\t\treturn enc.Encode(errorResponse{Error: err.Error()})\n\t\t}\n\t\tlvl.SetLevel(requestedLvl)\n\t\treturn enc.Encode(payload{Level: lvl.Level()})\n\n\tdefault:\n\t\tw.WriteHeader(http.StatusMethodNotAllowed)\n\t\treturn enc.Encode(errorResponse{\n\t\t\tError: "Only GET and PUT are supported.",\n\t\t})\n\t}\n}\n\n// Decodes incoming PUT requests and returns the requested logging level.\nfunc decodePutRequest(contentType string, r *http.Request) (zapcore.Level, error) {\n\tif contentType == "application/x-www-form-urlencoded" {\n\t\treturn decodePutURL(r)\n\t}\n\treturn decodePutJSON(r.Body)\n}\n\nfunc decodePutURL(r *http.Request) (zapcore.Level, error) {\n\tlvl := r.FormValue("level")\n\tif lvl == "" {\n\t\treturn 0, errors.New("must specify logging level")\n\t}\n\tvar l zapcore.Level\n\tif err := l.UnmarshalText([]byte(lvl)); err != nil {\n\t\treturn 0, err\n\t}\n\treturn l, nil\n}\n\nfunc decodePutJSON(body io.Reader) (zapcore.Level, error) {\n\tvar pld struct {\n\t\tLevel *zapcore.Level `json:"level"`\n\t}\n\tif err := json.NewDecoder(body).Decode(&pld); err != nil {\n\t\treturn 0, fmt.Errorf("malformed request body: %v", err)\n\t}\n\tif pld.Level == nil {\n\t\treturn 0, errors.New("must specify logging level")\n\t}\n\treturn *pld.Level, nil\n}\n',
            'logger.go': '// Copyright (c) 2016 Uber Technologies, Inc.\n//\n// Permission is hereby granted, free of charge, to any person obtaining a copy\n// of this software and associated documentation files (the "Software"), to deal\n// in the Software without restriction, including without limitation the rights\n// to use, copy, modify, merge, publish, distribute, sublicense, and/or sell\n// copies of the Software, and to permit persons to whom the Software is\n// furnished to do so, subject to the following conditions:\n//\n// The above copyright notice and this permission notice shall be included in\n// all copies or substantial portions of the Software.\n//\n// THE SOFTWARE IS PROVIDED "AS IS", WITHOUT WARRANTY OF ANY KIND, EXPRESS OR\n// IMPLIED, INCLUDING BUT NOT LIMITED TO THE WARRANTIES OF MERCHANTABILITY,\n// FITNESS FOR A PARTICULAR PURPOSE AND NONINFRINGEMENT. IN NO EVENT SHALL THE\n// AUTHORS OR COPYRIGHT HOLDERS BE LIABLE FOR ANY CLAIM, DAMAGES OR OTHER\n// LIABILITY, WHETHER IN AN ACTION OF CONTRACT, TORT OR OTHERWISE, ARISING FROM,\n// OUT OF OR IN CONNECTION WITH THE SOFTWARE OR THE USE OR OTHER DEALINGS IN\n// THE SOFTWARE.\n\npackage zap\n\nimport (\n\t"fmt"\n\t"io"\n\t"os"\n\t"strings"\n\n\t"go.uber.org/zap/internal/bufferpool"\n\t"go.uber.org/zap/internal/stacktrace"\n\t"go.uber.org/zap/zapcore"\n)\n\n// A Logger provides fast, leveled, structured logging. All methods are safe\n// for concurrent use.\n//\n// The Logger is designed for contexts in which every microsecond and every\n// allocation matters, so its API intentionally favors performance and type\n// safety over brevity. For most applications, the SugaredLogger strikes a\n// better balance between performance and ergonomics.\ntype Logger struct {\n\tcore zapcore.Core\n\n\tdevelopment bool\n\taddCaller   bool\n\tonPanic     zapcore.CheckWriteHook // default is WriteThenPanic\n\tonFatal     zapcore.CheckWriteHook // default is WriteThenFatal\n\n\tname        string\n\terrorOutput zapcore.WriteSyncer\n\n\taddStack zapcore.LevelEnabler\n\n\tcallerSkip int\n\n\tclock zapcore.Clock\n}\n\n// New constructs a new Logger from the provided zapcore.Core and Options. If\n// the passed zapcore.Core is nil, it falls back to using a no-op\n// implementation.\n//\n// This is the most flexible way to construct a Logger, but also the most\n// verbose. For typical use cases, the highly-opinionated presets\n// (NewProduction, NewDevelopment, and NewExample) or the Config struct are\n// more convenient.\n//\n// For sample code, see the package-level AdvancedConfiguration example.\nfunc New(core zapcore.Core, options ...Option) *Logger {\n\tif core == nil {\n\t\treturn NewNop()\n\t}\n\tlog := &Logger{\n\t\tcore:        core,\n\t\terrorOutput: zapcore.Lock(os.Stderr),\n\t\taddStack:    zapcore.FatalLevel + 1,\n\t\tclock:       zapcore.DefaultClock,\n\t}\n\treturn log.WithOptions(options...)\n}\n\n// NewNop returns a no-op Logger. It never writes out logs or internal errors,\n// and it never runs user-defined hooks.\n//\n// Using WithOptions to replace the Core or error output of a no-op Logger can\n// re-enable logging.\nfunc NewNop() *Logger {\n\treturn &Logger{\n\t\tcore:        zapcore.NewNopCore(),\n\t\terrorOutput: zapcore.AddSync(io.Discard),\n\t\taddStack:    zapcore.FatalLevel + 1,\n\t\tclock:       zapcore.DefaultClock,\n\t}\n}\n\n// NewProduction builds a sensible production Logger that writes InfoLevel and\n// above logs to standard error as JSON.\n//\n// It\'s a shortcut for NewProductionConfig().Build(...Option).\nfunc NewProduction(options ...Option) (*Logger, error) {\n\treturn NewProductionConfig().Build(options...)\n}\n\n// NewDevelopment builds a development Logger that writes DebugLevel and above\n// logs to standard error in a human-friendly format.\n//\n// It\'s a shortcut for NewDevelopmentConfig().Build(...Option).\nfunc NewDevelopment(options ...Option) (*Logger, error) {\n\treturn NewDevelopmentConfig().Build(options...)\n}\n\n// Must is a helper that wraps a call to a function returning (*Logger, error)\n// and panics if the error is non-nil. It is intended for use in variable\n// initialization such as:\n//\n//\tvar logger = zap.Must(zap.NewProduction())\nfunc Must(logger *Logger, err error) *Logger {\n\tif err != nil {\n\t\tpanic(err)\n\t}\n\n\treturn logger\n}\n\n// NewExample builds a Logger that\'s designed for use in zap\'s testable\n// examples. It writes DebugLevel and above logs to standard out as JSON, but\n// omits the timestamp and calling function to keep example output\n// short and deterministic.\nfunc NewExample(options ...Option) *Logger {\n\tencoderCfg := zapcore.EncoderConfig{\n\t\tMessageKey:     "msg",\n\t\tLevelKey:       "level",\n\t\tNameKey:        "logger",\n\t\tEncodeLevel:    zapcore.LowercaseLevelEncoder,\n\t\tEncodeTime:     zapcore.ISO8601TimeEncoder,\n\t\tEncodeDuration: zapcore.StringDurationEncoder,\n\t}\n\tcore := zapcore.NewCore(zapcore.NewJSONEncoder(encoderCfg), os.Stdout, DebugLevel)\n\treturn New(core).WithOptions(options...)\n}\n\n// Sugar wraps the Logger to provide a more ergonomic, but slightly slower,\n// API. Sugaring a Logger is quite inexpensive, so it\'s reasonable for a\n// single application to use both Loggers and SugaredLoggers, converting\n// between them on the boundaries of performance-sensitive code.\nfunc (log *Logger) Sugar() *SugaredLogger {\n\tcore := log.clone()\n\tcore.callerSkip += 2\n\treturn &SugaredLogger{core}\n}\n\n// Named adds a new path segment to the logger\'s name. Segments are joined by\n// periods. By default, Loggers are unnamed.\nfunc (log *Logger) Named(s string) *Logger {\n\tif s == "" {\n\t\treturn log\n\t}\n\tl := log.clone()\n\tif log.name == "" {\n\t\tl.name = s\n\t} else {\n\t\tl.name = strings.Join([]string{l.name, s}, ".")\n\t}\n\treturn l\n}\n\n// WithOptions clones the current Logger, applies the supplied Options, and\n// returns the resulting Logger. It\'s safe to use concurrently.\nfunc (log *Logger) WithOptions(opts ...Option) *Logger {\n\tc := log.clone()\n\tfor _, opt := range opts {\n\t\topt.apply(c)\n\t}\n\treturn c\n}\n\n// With creates a child logger and adds structured context to it. Fields added\n// to the child don\'t affect the parent, and vice versa. Any fields that\n// require evaluation (such as Objects) are evaluated upon invocation of With.\nfunc (log *Logger) With(fields ...Field) *Logger {\n\tif len(fields) == 0 {\n\t\treturn log\n\t}\n\tl := log.clone()\n\tl.core = l.core.With(fields)\n\treturn l\n}\n\n// WithLazy creates a child logger and adds structured context to it lazily.\n//\n// The fields are evaluated only if the logger is further chained with [With]\n// or is written to with any of the log level methods.\n// Until that occurs, the logger may retain references to objects inside the fields,\n// and logging will reflect the state of an object at the time of logging,\n// not the time of WithLazy().\n//\n// WithLazy provides a worthwhile performance optimization for contextual loggers\n// when the likelihood of using the child logger is low,\n// such as error paths and rarely taken branches.\n//\n// Similar to [With], fields added to the child don\'t affect the parent, and vice versa.\nfunc (log *Logger) WithLazy(fields ...Field) *Logger {\n\tif len(fields) == 0 {\n\t\treturn log\n\t}\n\treturn log.WithOptions(WrapCore(func(core zapcore.Core) zapcore.Core {\n\t\treturn zapcore.NewLazyWith(core, fields)\n\t}))\n}\n\n// Level reports the minimum enabled level for this logger.\n//\n// For NopLoggers, this is [zapcore.InvalidLevel].\nfunc (log *Logger) Level() zapcore.Level {\n\treturn zapcore.LevelOf(log.core)\n}\n\n// Check returns a CheckedEntry if logging a message at the specified level\n// is enabled. It\'s a completely optional optimization; in high-performance\n// applications, Check can help avoid allocating a slice to hold fields.\nfunc (log *Logger) Check(lvl zapcore.Level, msg string) *zapcore.CheckedEntry {\n\treturn log.check(lvl, msg)\n}\n\n// Log logs a message at the specified level. The message includes any fields\n// passed at the log site, as well as any fields accumulated on the logger.\n// Any Fields that require  evaluation (such as Objects) are evaluated upon\n// invocation of Log.\nfunc (log *Logger) Log(lvl zapcore.Level, msg string, fields ...Field) {\n\tif ce := log.check(lvl, msg); ce != nil {\n\t\tce.Write(fields...)\n\t}\n}\n\n// Debug logs a message at DebugLevel. The message includes any fields passed\n// at the log site, as well as any fields accumulated on the logger.\nfunc (log *Logger) Debug(msg string, fields ...Field) {\n\tif ce := log.check(DebugLevel, msg); ce != nil {\n\t\tce.Write(fields...)\n\t}\n}\n\n// Info logs a message at InfoLevel. The message includes any fields passed\n// at the log site, as well as any fields accumulated on the logger.\nfunc (log *Logger) Info(msg string, fields ...Field) {\n\tif ce := log.check(InfoLevel, msg); ce != nil {\n\t\tce.Write(fields...)\n\t}\n}\n\n// Warn logs a message at WarnLevel. The message includes any fields passed\n// at the log site, as well as any fields accumulated on the logger.\nfunc (log *Logger) Warn(msg string, fields ...Field) {\n\tif ce := log.check(WarnLevel, msg); ce != nil {\n\t\tce.Write(fields...)\n\t}\n}\n\n// Error logs a message at ErrorLevel. The message includes any fields passed\n// at the log site, as well as any fields accumulated on the logger.\nfunc (log *Logger) Error(msg string, fields ...Field) {\n\tif ce := log.check(ErrorLevel, msg); ce != nil {\n\t\tce.Write(fields...)\n\t}\n}\n\n// DPanic logs a message at DPanicLevel. The message includes any fields\n// passed at the log site, as well as any fields accumulated on the logger.\n//\n// If the logger is in development mode, it then panics (DPanic means\n// "development panic"). This is useful for catching errors that are\n// recoverable, but shouldn\'t ever happen.\nfunc (log *Logger) DPanic(msg string, fields ...Field) {\n\tif ce := log.check(DPanicLevel, msg); ce != nil {\n\t\tce.Write(fields...)\n\t}\n}\n\n// Panic logs a message at PanicLevel. The message includes any fields passed\n// at the log site, as well as any fields accumulated on the logger.\n//\n// The logger then panics, even if logging at PanicLevel is disabled.\nfunc (log *Logger) Panic(msg string, fields ...Field) {\n\tif ce := log.check(PanicLevel, msg); ce != nil {\n\t\tce.Write(fields...)\n\t}\n}\n\n// Fatal logs a message at FatalLevel. The message includes any fields passed\n// at the log site, as well as any fields accumulated on the logger.\n//\n// The logger then calls os.Exit(1), even if logging at FatalLevel is\n// disabled.\nfunc (log *Logger) Fatal(msg string, fields ...Field) {\n\tif ce := log.check(FatalLevel, msg); ce != nil {\n\t\tce.Write(fields...)\n\t}\n}\n\n// Sync calls the underlying Core\'s Sync method, flushing any buffered log\n// entries. Applications should take care to call Sync before exiting.\nfunc (log *Logger) Sync() error {\n\treturn log.core.Sync()\n}\n\n// Core returns the Logger\'s underlying zapcore.Core.\nfunc (log *Logger) Core() zapcore.Core {\n\treturn log.core\n}\n\n// Name returns the Logger\'s underlying name,\n// or an empty string if the logger is unnamed.\nfunc (log *Logger) Name() string {\n\treturn log.name\n}\n\nfunc (log *Logger) clone() *Logger {\n\tclone := *log\n\treturn &clone\n}\n\nfunc (log *Logger) check(lvl zapcore.Level, msg string) *zapcore.CheckedEntry {\n\t// Logger.check must always be called directly by a method in the\n\t// Logger interface (e.g., Check, Info, Fatal).\n\t// This skips Logger.check and the Info/Fatal/Check/etc. method that\n\t// called it.\n\tconst callerSkipOffset = 2\n\n\t// Check the level first to reduce the cost of disabled log calls.\n\t// Since Panic and higher may exit, we skip the optimization for those levels.\n\tif lvl < zapcore.DPanicLevel && !log.core.Enabled(lvl) {\n\t\treturn nil\n\t}\n\n\t// Create basic checked entry thru the core; this will be non-nil if the\n\t// log message will actually be written somewhere.\n\tent := zapcore.Entry{\n\t\tLoggerName: log.name,\n\t\tTime:       log.clock.Now(),\n\t\tLevel:      lvl,\n\t\tMessage:    msg,\n\t}\n\tce := log.core.Check(ent, nil)\n\twillWrite := ce != nil\n\n\t// Set up any required terminal behavior.\n\tswitch ent.Level {\n\tcase zapcore.PanicLevel:\n\t\tce = ce.After(ent, terminalHookOverride(zapcore.WriteThenPanic, log.onPanic))\n\tcase zapcore.FatalLevel:\n\t\tce = ce.After(ent, terminalHookOverride(zapcore.WriteThenFatal, log.onFatal))\n\tcase zapcore.DPanicLevel:\n\t\tif log.development {\n\t\t\tce = ce.After(ent, terminalHookOverride(zapcore.WriteThenPanic, log.onPanic))\n\t\t}\n\t}\n\n\t// Only do further annotation if we\'re going to write this message; checked\n\t// entries that exist only for terminal behavior don\'t benefit from\n\t// annotation.\n\tif !willWrite {\n\t\treturn ce\n\t}\n\n\t// Thread the error output through to the CheckedEntry.\n\tce.ErrorOutput = log.errorOutput\n\n\taddStack := log.addStack.Enabled(ce.Level)\n\tif !log.addCaller && !addStack {\n\t\treturn ce\n\t}\n\n\t// Adding the caller or stack trace requires capturing the callers of\n\t// this function. We\'ll share information between these two.\n\tstackDepth := stacktrace.First\n\tif addStack {\n\t\tstackDepth = stacktrace.Full\n\t}\n\tstack := stacktrace.Capture(log.callerSkip+callerSkipOffset, stackDepth)\n\tdefer stack.Free()\n\n\tif stack.Count() == 0 {\n\t\tif log.addCaller {\n\t\t\tfmt.Fprintf(log.errorOutput, "%v Logger.check error: failed to get caller\\n", ent.Time.UTC())\n\t\t\t_ = log.errorOutput.Sync()\n\t\t}\n\t\treturn ce\n\t}\n\n\tframe, more := stack.Next()\n\n\tif log.addCaller {\n\t\tce.Caller = zapcore.EntryCaller{\n\t\t\tDefined:  frame.PC != 0,\n\t\t\tPC:       frame.PC,\n\t\t\tFile:     frame.File,\n\t\t\tLine:     frame.Line,\n\t\t\tFunction: frame.Function,\n\t\t}\n\t}\n\n\tif addStack {\n\t\tbuffer := bufferpool.Get()\n\t\tdefer buffer.Free()\n\n\t\tstackfmt := stacktrace.NewFormatter(buffer)\n\n\t\t// We\'ve already extracted the first frame, so format that\n\t\t// separately and defer to stackfmt for the rest.\n\t\tstackfmt.FormatFrame(frame)\n\t\tif more {\n\t\t\tstackfmt.FormatStack(stack)\n\t\t}\n\t\tce.Stack = buffer.String()\n\t}\n\n\treturn ce\n}\n\nfunc terminalHookOverride(defaultHook, override zapcore.CheckWriteHook) zapcore.CheckWriteHook {\n\t// A nil or WriteThenNoop hook will lead to continued execution after\n\t// a Panic or Fatal log entry, which is unexpected. For example,\n\t//\n\t//   f, err := os.Open(..)\n\t//   if err != nil {\n\t//     log.Fatal("cannot open", zap.Error(err))\n\t//   }\n\t//   fmt.Println(f.Name())\n\t//\n\t// The f.Name() will panic if we continue execution after the log.Fatal.\n\tif override == nil || override == zapcore.WriteThenNoop {\n\t\treturn defaultHook\n\t}\n\treturn override\n}\n',
            'options.go': '// Copyright (c) 2016 Uber Technologies, Inc.\n//\n// Permission is hereby granted, free of charge, to any person obtaining a copy\n// of this software and associated documentation files (the "Software"), to deal\n// in the Software without restriction, including without limitation the rights\n// to use, copy, modify, merge, publish, distribute, sublicense, and/or sell\n// copies of the Software, and to permit persons to whom the Software is\n// furnished to do so, subject to the following conditions:\n//\n// The above copyright notice and this permission notice shall be included in\n// all copies or substantial portions of the Software.\n//\n// THE SOFTWARE IS PROVIDED "AS IS", WITHOUT WARRANTY OF ANY KIND, EXPRESS OR\n// IMPLIED, INCLUDING BUT NOT LIMITED TO THE WARRANTIES OF MERCHANTABILITY,\n// FITNESS FOR A PARTICULAR PURPOSE AND NONINFRINGEMENT. IN NO EVENT SHALL THE\n// AUTHORS OR COPYRIGHT HOLDERS BE LIABLE FOR ANY CLAIM, DAMAGES OR OTHER\n// LIABILITY, WHETHER IN AN ACTION OF CONTRACT, TORT OR OTHERWISE, ARISING FROM,\n// OUT OF OR IN CONNECTION WITH THE SOFTWARE OR THE USE OR OTHER DEALINGS IN\n// THE SOFTWARE.\n\npackage zap\n\nimport (\n\t"fmt"\n\n\t"go.uber.org/zap/zapcore"\n)\n\n// An Option configures a Logger.\ntype Option interface {\n\tapply(*Logger)\n}\n\n// optionFunc wraps a func so it satisfies the Option interface.\ntype optionFunc func(*Logger)\n\nfunc (f optionFunc) apply(log *Logger) {\n\tf(log)\n}\n\n// WrapCore wraps or replaces the Logger\'s underlying zapcore.Core.\nfunc WrapCore(f func(zapcore.Core) zapcore.Core) Option {\n\treturn optionFunc(func(log *Logger) {\n\t\tlog.core = f(log.core)\n\t})\n}\n\n// Hooks registers functions which will be called each time the Logger writes\n// out an Entry. Repeated use of Hooks is additive.\n//\n// Hooks are useful for simple side effects, like capturing metrics for the\n// number of emitted logs. More complex side effects, including anything that\n// requires access to the Entry\'s structured fields, should be implemented as\n// a zapcore.Core instead. See zapcore.RegisterHooks for details.\nfunc Hooks(hooks ...func(zapcore.Entry) error) Option {\n\treturn optionFunc(func(log *Logger) {\n\t\tlog.core = zapcore.RegisterHooks(log.core, hooks...)\n\t})\n}\n\n// Fields adds fields to the Logger.\nfunc Fields(fs ...Field) Option {\n\treturn optionFunc(func(log *Logger) {\n\t\tlog.core = log.core.With(fs)\n\t})\n}\n\n// ErrorOutput sets the destination for errors generated by the Logger. Note\n// that this option only affects internal errors; for sample code that sends\n// error-level logs to a different location from info- and debug-level logs,\n// see the package-level AdvancedConfiguration example.\n//\n// The supplied WriteSyncer must be safe for concurrent use. The Open and\n// zapcore.Lock functions are the simplest ways to protect files with a mutex.\nfunc ErrorOutput(w zapcore.WriteSyncer) Option {\n\treturn optionFunc(func(log *Logger) {\n\t\tlog.errorOutput = w\n\t})\n}\n\n// Development puts the logger in development mode, which makes DPanic-level\n// logs panic instead of simply logging an error.\nfunc Development() Option {\n\treturn optionFunc(func(log *Logger) {\n\t\tlog.development = true\n\t})\n}\n\n// AddCaller configures the Logger to annotate each message with the filename,\n// line number, and function name of zap\'s caller. See also WithCaller.\nfunc AddCaller() Option {\n\treturn WithCaller(true)\n}\n\n// WithCaller configures the Logger to annotate each message with the filename,\n// line number, and function name of zap\'s caller, or not, depending on the\n// value of enabled. This is a generalized form of AddCaller.\nfunc WithCaller(enabled bool) Option {\n\treturn optionFunc(func(log *Logger) {\n\t\tlog.addCaller = enabled\n\t})\n}\n\n// AddCallerSkip increases the number of callers skipped by caller annotation\n// (as enabled by the AddCaller option). When building wrappers around the\n// Logger and SugaredLogger, supplying this Option prevents zap from always\n// reporting the wrapper code as the caller.\nfunc AddCallerSkip(skip int) Option {\n\treturn optionFunc(func(log *Logger) {\n\t\tlog.callerSkip += skip\n\t})\n}\n\n// AddStacktrace configures the Logger to record a stack trace for all messages at\n// or above a given level.\nfunc AddStacktrace(lvl zapcore.LevelEnabler) Option {\n\treturn optionFunc(func(log *Logger) {\n\t\tlog.addStack = lvl\n\t})\n}\n\n// IncreaseLevel increase the level of the logger. It has no effect if\n// the passed in level tries to decrease the level of the logger.\nfunc IncreaseLevel(lvl zapcore.LevelEnabler) Option {\n\treturn optionFunc(func(log *Logger) {\n\t\tcore, err := zapcore.NewIncreaseLevelCore(log.core, lvl)\n\t\tif err != nil {\n\t\t\tfmt.Fprintf(log.errorOutput, "failed to IncreaseLevel: %v\\n", err)\n\t\t} else {\n\t\t\tlog.core = core\n\t\t}\n\t})\n}\n\n// WithPanicHook sets a CheckWriteHook to run on Panic/DPanic logs.\n// Zap will call this hook after writing a log statement with a Panic/DPanic level.\n//\n// For example, the following builds a logger that will exit the current\n// goroutine after writing a Panic/DPanic log message, but it will not start a panic.\n//\n//\tzap.New(core, zap.WithPanicHook(zapcore.WriteThenGoexit))\n//\n// This is useful for testing Panic/DPanic log output.\nfunc WithPanicHook(hook zapcore.CheckWriteHook) Option {\n\treturn optionFunc(func(log *Logger) {\n\t\tlog.onPanic = hook\n\t})\n}\n\n// OnFatal sets the action to take on fatal logs.\n//\n// Deprecated: Use [WithFatalHook] instead.\nfunc OnFatal(action zapcore.CheckWriteAction) Option {\n\treturn WithFatalHook(action)\n}\n\n// WithFatalHook sets a CheckWriteHook to run on fatal logs.\n// Zap will call this hook after writing a log statement with a Fatal level.\n//\n// For example, the following builds a logger that will exit the current\n// goroutine after writing a fatal log message, but it will not exit the\n// program.\n//\n//\tzap.New(core, zap.WithFatalHook(zapcore.WriteThenGoexit))\n//\n// It is important that the provided CheckWriteHook stops the control flow at\n// the current statement to meet expectations of callers of the logger.\n// We recommend calling os.Exit or runtime.Goexit inside custom hooks at\n// minimum.\nfunc WithFatalHook(hook zapcore.CheckWriteHook) Option {\n\treturn optionFunc(func(log *Logger) {\n\t\tlog.onFatal = hook\n\t})\n}\n\n// WithClock specifies the clock used by the logger to determine the current\n// time for logged entries. Defaults to the system clock with time.Now.\nfunc WithClock(clock zapcore.Clock) Option {\n\treturn optionFunc(func(log *Logger) {\n\t\tlog.clock = clock\n\t})\n}\n',
            'zapcore/console_encoder.go': '// Copyright (c) 2016 Uber Technologies, Inc.\n//\n// Permission is hereby granted, free of charge, to any person obtaining a copy\n// of this software and associated documentation files (the "Software"), to deal\n// in the Software without restriction, including without limitation the rights\n// to use, copy, modify, merge, publish, distribute, sublicense, and/or sell\n// copies of the Software, and to permit persons to whom the Software is\n// furnished to do so, subject to the following conditions:\n//\n// The above copyright notice and this permission notice shall be included in\n// all copies or substantial portions of the Software.\n//\n// THE SOFTWARE IS PROVIDED "AS IS", WITHOUT WARRANTY OF ANY KIND, EXPRESS OR\n// IMPLIED, INCLUDING BUT NOT LIMITED TO THE WARRANTIES OF MERCHANTABILITY,\n// FITNESS FOR A PARTICULAR PURPOSE AND NONINFRINGEMENT. IN NO EVENT SHALL THE\n// AUTHORS OR COPYRIGHT HOLDERS BE LIABLE FOR ANY CLAIM, DAMAGES OR OTHER\n// LIABILITY, WHETHER IN AN ACTION OF CONTRACT, TORT OR OTHERWISE, ARISING FROM,\n// OUT OF OR IN CONNECTION WITH THE SOFTWARE OR THE USE OR OTHER DEALINGS IN\n// THE SOFTWARE.\n\npackage zapcore\n\nimport (\n\t"fmt"\n\n\t"go.uber.org/zap/buffer"\n\t"go.uber.org/zap/internal/bufferpool"\n\t"go.uber.org/zap/internal/pool"\n)\n\nvar _sliceEncoderPool = pool.New(func() *sliceArrayEncoder {\n\treturn &sliceArrayEncoder{\n\t\telems: make([]interface{}, 0, 2),\n\t}\n})\n\nfunc getSliceEncoder() *sliceArrayEncoder {\n\treturn _sliceEncoderPool.Get()\n}\n\nfunc putSliceEncoder(e *sliceArrayEncoder) {\n\te.elems = e.elems[:0]\n\t_sliceEncoderPool.Put(e)\n}\n\ntype consoleEncoder struct {\n\t*jsonEncoder\n}\n\n// NewConsoleEncoder creates an encoder whose output is designed for human -\n// rather than machine - consumption. It serializes the core log entry data\n// (message, level, timestamp, etc.) in a plain-text format and leaves the\n// structured context as JSON.\n//\n// Note that although the console encoder doesn\'t use the keys specified in the\n// encoder configuration, it will omit any element whose key is set to the empty\n// string.\nfunc NewConsoleEncoder(cfg EncoderConfig) Encoder {\n\tif cfg.ConsoleSeparator == "" {\n\t\t// Use a default delimiter of \'\\t\' for backwards compatibility\n\t\tcfg.ConsoleSeparator = "\\t"\n\t}\n\treturn consoleEncoder{newJSONEncoder(cfg, true)}\n}\n\nfunc (c consoleEncoder) Clone() Encoder {\n\treturn consoleEncoder{c.jsonEncoder.Clone().(*jsonEncoder)}\n}\n\nfunc (c consoleEncoder) EncodeEntry(ent Entry, fields []Field) (*buffer.Buffer, error) {\n\tline := bufferpool.Get()\n\n\t// We don\'t want the entry\'s metadata to be quoted and escaped (if it\'s\n\t// encoded as strings), which means that we can\'t use the JSON encoder. The\n\t// simplest option is to use the memory encoder and fmt.Fprint.\n\t//\n\t// If this ever becomes a performance bottleneck, we can implement\n\t// ArrayEncoder for our plain-text format.\n\tarr := getSliceEncoder()\n\tif c.TimeKey != "" && c.EncodeTime != nil && !ent.Time.IsZero() {\n\t\tc.EncodeTime(ent.Time, arr)\n\t}\n\tif c.LevelKey != "" && c.EncodeLevel != nil {\n\t\tc.EncodeLevel(ent.Level, arr)\n\t}\n\tif ent.LoggerName != "" && c.NameKey != "" {\n\t\tnameEncoder := c.EncodeName\n\n\t\tif nameEncoder == nil {\n\t\t\t// Fall back to FullNameEncoder for backward compatibility.\n\t\t\tnameEncoder = FullNameEncoder\n\t\t}\n\n\t\tnameEncoder(ent.LoggerName, arr)\n\t}\n\tif ent.Caller.Defined {\n\t\tif c.CallerKey != "" && c.EncodeCaller != nil {\n\t\t\tc.EncodeCaller(ent.Caller, arr)\n\t\t}\n\t\tif c.FunctionKey != "" {\n\t\t\tarr.AppendString(ent.Caller.Function)\n\t\t}\n\t}\n\tfor i := range arr.elems {\n\t\tif i > 0 {\n\t\t\tline.AppendString(c.ConsoleSeparator)\n\t\t}\n\t\tfmt.Fprint(line, arr.elems[i])\n\t}\n\tputSliceEncoder(arr)\n\n\t// Add the message itself.\n\tif c.MessageKey != "" {\n\t\tc.addSeparatorIfNecessary(line)\n\t\tline.AppendString(ent.Message)\n\t}\n\n\t// Add any structured context.\n\tc.writeContext(line, fields)\n\n\t// If there\'s no stacktrace key, honor that; this allows users to force\n\t// single-line output.\n\tif ent.Stack != "" && c.StacktraceKey != "" {\n\t\tline.AppendByte(\'\\n\')\n\t\tline.AppendString(ent.Stack)\n\t}\n\n\tline.AppendString(c.LineEnding)\n\treturn line, nil\n}\n\nfunc (c consoleEncoder) writeContext(line *buffer.Buffer, extra []Field) {\n\tcontext := c.jsonEncoder.Clone().(*jsonEncoder)\n\tdefer func() {\n\t\t// putJSONEncoder assumes the buffer is still used, but we write out the buffer so\n\t\t// we can free it.\n\t\tcontext.buf.Free()\n\t\tputJSONEncoder(context)\n\t}()\n\n\taddFields(context, extra)\n\tcontext.closeOpenNamespaces()\n\tif context.buf.Len() == 0 {\n\t\treturn\n\t}\n\n\tc.addSeparatorIfNecessary(line)\n\tline.AppendByte(\'{\')\n\tline.Write(context.buf.Bytes())\n\tline.AppendByte(\'}\')\n}\n\nfunc (c consoleEncoder) addSeparatorIfNecessary(line *buffer.Buffer) {\n\tif line.Len() > 0 {\n\t\tline.AppendString(c.ConsoleSeparator)\n\t}\n}\n',
            'zapcore/entry.go': '// Copyright (c) 2016 Uber Technologies, Inc.\n//\n// Permission is hereby granted, free of charge, to any person obtaining a copy\n// of this software and associated documentation files (the "Software"), to deal\n// in the Software without restriction, including without limitation the rights\n// to use, copy, modify, merge, publish, distribute, sublicense, and/or sell\n// copies of the Software, and to permit persons to whom the Software is\n// furnished to do so, subject to the following conditions:\n//\n// The above copyright notice and this permission notice shall be included in\n// all copies or substantial portions of the Software.\n//\n// THE SOFTWARE IS PROVIDED "AS IS", WITHOUT WARRANTY OF ANY KIND, EXPRESS OR\n// IMPLIED, INCLUDING BUT NOT LIMITED TO THE WARRANTIES OF MERCHANTABILITY,\n// FITNESS FOR A PARTICULAR PURPOSE AND NONINFRINGEMENT. IN NO EVENT SHALL THE\n// AUTHORS OR COPYRIGHT HOLDERS BE LIABLE FOR ANY CLAIM, DAMAGES OR OTHER\n// LIABILITY, WHETHER IN AN ACTION OF CONTRACT, TORT OR OTHERWISE, ARISING FROM,\n// OUT OF OR IN CONNECTION WITH THE SOFTWARE OR THE USE OR OTHER DEALINGS IN\n// THE SOFTWARE.\n\npackage zapcore\n\nimport (\n\t"fmt"\n\t"runtime"\n\t"strings"\n\t"time"\n\n\t"go.uber.org/multierr"\n\t"go.uber.org/zap/internal/bufferpool"\n\t"go.uber.org/zap/internal/exit"\n\t"go.uber.org/zap/internal/pool"\n)\n\nvar _cePool = pool.New(func() *CheckedEntry {\n\t// Pre-allocate some space for cores.\n\treturn &CheckedEntry{\n\t\tcores: make([]Core, 4),\n\t}\n})\n\nfunc getCheckedEntry() *CheckedEntry {\n\tce := _cePool.Get()\n\tce.reset()\n\treturn ce\n}\n\nfunc putCheckedEntry(ce *CheckedEntry) {\n\tif ce == nil {\n\t\treturn\n\t}\n\t_cePool.Put(ce)\n}\n\n// NewEntryCaller makes an EntryCaller from the return signature of\n// runtime.Caller.\nfunc NewEntryCaller(pc uintptr, file string, line int, ok bool) EntryCaller {\n\tif !ok {\n\t\treturn EntryCaller{}\n\t}\n\treturn EntryCaller{\n\t\tPC:      pc,\n\t\tFile:    file,\n\t\tLine:    line,\n\t\tDefined: true,\n\t}\n}\n\n// EntryCaller represents the caller of a logging function.\ntype EntryCaller struct {\n\tDefined  bool\n\tPC       uintptr\n\tFile     string\n\tLine     int\n\tFunction string\n}\n\n// String returns the full path and line number of the caller.\nfunc (ec EntryCaller) String() string {\n\treturn ec.FullPath()\n}\n\n// FullPath returns a /full/path/to/package/file:line description of the\n// caller.\nfunc (ec EntryCaller) FullPath() string {\n\tif !ec.Defined {\n\t\treturn "undefined"\n\t}\n\tbuf := bufferpool.Get()\n\tbuf.AppendString(ec.File)\n\tbuf.AppendByte(\':\')\n\tbuf.AppendInt(int64(ec.Line))\n\tcaller := buf.String()\n\tbuf.Free()\n\treturn caller\n}\n\n// TrimmedPath returns a package/file:line description of the caller,\n// preserving only the leaf directory name and file name.\nfunc (ec EntryCaller) TrimmedPath() string {\n\tif !ec.Defined {\n\t\treturn "undefined"\n\t}\n\t// nb. To make sure we trim the path correctly on Windows too, we\n\t// counter-intuitively need to use \'/\' and *not* os.PathSeparator here,\n\t// because the path given originates from Go stdlib, specifically\n\t// runtime.Caller() which (as of Mar/17) returns forward slashes even on\n\t// Windows.\n\t//\n\t// See https://github.com/golang/go/issues/3335\n\t// and https://github.com/golang/go/issues/18151\n\t//\n\t// for discussion on the issue on Go side.\n\t//\n\t// Find the last separator.\n\t//\n\tidx := strings.LastIndexByte(ec.File, \'/\')\n\tif idx == -1 {\n\t\treturn ec.FullPath()\n\t}\n\t// Find the penultimate separator.\n\tidx = strings.LastIndexByte(ec.File[:idx], \'/\')\n\tif idx == -1 {\n\t\treturn ec.FullPath()\n\t}\n\tbuf := bufferpool.Get()\n\t// Keep everything after the penultimate separator.\n\tbuf.AppendString(ec.File[idx+1:])\n\tbuf.AppendByte(\':\')\n\tbuf.AppendInt(int64(ec.Line))\n\tcaller := buf.String()\n\tbuf.Free()\n\treturn caller\n}\n\n// An Entry represents a complete log message. The entry\'s structured context\n// is already serialized, but the log level, time, message, and call site\n// information are available for inspection and modification. Any fields left\n// empty will be omitted when encoding.\n//\n// Entries are pooled, so any functions that accept them MUST be careful not to\n// retain references to them.\ntype Entry struct {\n\tLevel      Level\n\tTime       time.Time\n\tLoggerName string\n\tMessage    string\n\tCaller     EntryCaller\n\tStack      string\n}\n\n// CheckWriteHook is a custom action that may be executed after an entry is\n// written.\n//\n// Register one on a CheckedEntry with the After method.\n//\n//\tif ce := logger.Check(...); ce != nil {\n//\t  ce = ce.After(hook)\n//\t  ce.Write(...)\n//\t}\n//\n// You can configure the hook for Fatal log statements at the logger level with\n// the zap.WithFatalHook option.\ntype CheckWriteHook interface {\n\t// OnWrite is invoked with the CheckedEntry that was written and a list\n\t// of fields added with that entry.\n\t//\n\t// The list of fields DOES NOT include fields that were already added\n\t// to the logger with the With method.\n\tOnWrite(*CheckedEntry, []Field)\n}\n\n// CheckWriteAction indicates what action to take after a log entry is\n// processed. Actions are ordered in increasing severity.\ntype CheckWriteAction uint8\n\nconst (\n\t// WriteThenNoop indicates that nothing special needs to be done. It\'s the\n\t// default behavior.\n\tWriteThenNoop CheckWriteAction = iota\n\t// WriteThenGoexit runs runtime.Goexit after Write.\n\tWriteThenGoexit\n\t// WriteThenPanic causes a panic after Write.\n\tWriteThenPanic\n\t// WriteThenFatal causes an os.Exit(1) after Write.\n\tWriteThenFatal\n)\n\n// OnWrite implements the OnWrite method to keep CheckWriteAction compatible\n// with the new CheckWriteHook interface which deprecates CheckWriteAction.\nfunc (a CheckWriteAction) OnWrite(ce *CheckedEntry, _ []Field) {\n\tswitch a {\n\tcase WriteThenGoexit:\n\t\truntime.Goexit()\n\tcase WriteThenPanic:\n\t\tpanic(ce.Message)\n\tcase WriteThenFatal:\n\t\texit.With(1)\n\t}\n}\n\nvar _ CheckWriteHook = CheckWriteAction(0)\n\n// CheckedEntry is an Entry together with a collection of Cores that have\n// already agreed to log it.\n//\n// CheckedEntry references should be created by calling AddCore or After on a\n// nil *CheckedEntry. References are returned to a pool after Write, and MUST\n// NOT be retained after calling their Write method.\ntype CheckedEntry struct {\n\tEntry\n\tErrorOutput WriteSyncer\n\tdirty       bool // best-effort detection of pool misuse\n\tafter       CheckWriteHook\n\tcores       []Core\n}\n\nfunc (ce *CheckedEntry) reset() {\n\tce.Entry = Entry{}\n\tce.ErrorOutput = nil\n\tce.dirty = false\n\tce.after = nil\n\tfor i := range ce.cores {\n\t\t// don\'t keep references to cores\n\t\tce.cores[i] = nil\n\t}\n\tce.cores = ce.cores[:0]\n}\n\n// Write writes the entry to the stored Cores, returns any errors, and returns\n// the CheckedEntry reference to a pool for immediate re-use. Finally, it\n// executes any required CheckWriteAction.\nfunc (ce *CheckedEntry) Write(fields ...Field) {\n\tif ce == nil {\n\t\treturn\n\t}\n\n\tif ce.dirty {\n\t\tif ce.ErrorOutput != nil {\n\t\t\t// Make a best effort to detect unsafe re-use of this CheckedEntry.\n\t\t\t// If the entry is dirty, log an internal error; because the\n\t\t\t// CheckedEntry is being used after it was returned to the pool,\n\t\t\t// the message may be an amalgamation from multiple call sites.\n\t\t\tfmt.Fprintf(ce.ErrorOutput, "%v Unsafe CheckedEntry re-use near Entry %+v.\\n", ce.Time, ce.Entry)\n\t\t\t_ = ce.ErrorOutput.Sync() // ignore error\n\t\t}\n\t\treturn\n\t}\n\tce.dirty = true\n\n\tvar err error\n\tfor i := range ce.cores {\n\t\terr = multierr.Append(err, ce.cores[i].Write(ce.Entry, fields))\n\t}\n\tif err != nil && ce.ErrorOutput != nil {\n\t\tfmt.Fprintf(ce.ErrorOutput, "%v write error: %v\\n", ce.Time, err)\n\t\t_ = ce.ErrorOutput.Sync() // ignore error\n\t}\n\n\thook := ce.after\n\tif hook != nil {\n\t\thook.OnWrite(ce, fields)\n\t}\n\tputCheckedEntry(ce)\n}\n\n// AddCore adds a Core that has agreed to log this CheckedEntry. It\'s intended to be\n// used by Core.Check implementations, and is safe to call on nil CheckedEntry\n// references.\nfunc (ce *CheckedEntry) AddCore(ent Entry, core Core) *CheckedEntry {\n\tif ce == nil {\n\t\tce = getCheckedEntry()\n\t\tce.Entry = ent\n\t}\n\tce.cores = append(ce.cores, core)\n\treturn ce\n}\n\n// Should sets this CheckedEntry\'s CheckWriteAction, which controls whether a\n// Core will panic or fatal after writing this log entry. Like AddCore, it\'s\n// safe to call on nil CheckedEntry references.\n//\n// Deprecated: Use [CheckedEntry.After] instead.\nfunc (ce *CheckedEntry) Should(ent Entry, should CheckWriteAction) *CheckedEntry {\n\treturn ce.After(ent, should)\n}\n\n// After sets this CheckEntry\'s CheckWriteHook, which will be called after this\n// log entry has been written. It\'s safe to call this on nil CheckedEntry\n// references.\nfunc (ce *CheckedEntry) After(ent Entry, hook CheckWriteHook) *CheckedEntry {\n\tif ce == nil {\n\t\tce = getCheckedEntry()\n\t\tce.Entry = ent\n\t}\n\tce.after = hook\n\treturn ce\n}\n',
        }
